internal final class ETGScaleTicketHelper
{
}

Method.Source:
/// <summary>
/// This method is lookup method for purchase agreements
/// </summary>
/// <param name = "sender"></param>
public static void lookupPurchAgreement(FormControl sender)
{

    Query                   query = new Query();
    QueryBuildDataSource    qbdsHeader, qbdsAgreement,qbdsVend, qbdsParty;
    QueryBuildRange         qbrStatus,qbrCompany;
    SysTableLookup          sysTableLookup;
    CompanyId               paramCompany;

    paramCompany   = ETGCanadaParameters::find().DefaultEntityForDocuments;
    sysTableLookup = SysTableLookup::newParameters(
    tableNum(PurchAgreementHeader),
    sender);

    if(ETGCanadaParameters::find().EnableScaleTcket == NoYes::Yes)
    {
        sysTableLookup.addLookupfield(fieldNum(PurchAgreementHeader, PurchNumberSequence));
        sysTableLookup.addLookupfield(fieldNum(PurchAgreementHeader, VendAccount));

        qbdsHeader = query.addDataSource(tableNum(PurchAgreementHeader));
        qbrCompany = qbdsHeader.addRange(fieldNum(PurchAgreementHeader, VendorDataAreaId));
        qbrCompany.value(queryValue(paramCompany));
        qbrStatus = qbdsHeader.addRange(fieldNum(AgreementHeader,AgreementState));
        qbrStatus.value(queryValue(AgreementState::Effective));

        // Descending order
        qbdsHeader.addSortField(
            fieldNum(PurchAgreementHeader, PurchNumberSequence),
            SortOrder::Descending);

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
    }
}
